var transpose = function(matrix) {
    const m = matrix.length, n = matrix[0].length;
    const out = Array.from({ length: n }, () => new Array(m));
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            out[j][i] = matrix[i][j];
        }
    }
    return out;
};
